    const _mock_url = try std.fmt.allocPrintSentinel(std.heap.c_allocator, "{s}/fixtures/stream_error_401", .{if (std.c.getenv("MOCK_SERVER_URL")) |v| std.mem.span(v) else "http://localhost:8080"}, 0);
    defer std.heap.c_allocator.free(_mock_url);
    var _client = try liter_llm.create_client("test-key", _mock_url, null, null, null);
    defer _client.free();
    const _result_json = _client.chat_stream("{\"messages\":[{\"content\":\"Hello\",\"role\":\"user\"}],\"model\":\"gpt-4\",\"stream\":true}") catch {
        try testing.expect(true); // Error occurred as expected
        return;
    };
    _ = _result_json;
}

