test "stream_with_tool_calls" {
    // Streaming chat completion where the assistant responds with a tool call across multiple chunks
    const _mock_url = try std.fmt.allocPrintSentinel(std.heap.c_allocator, "{s}/fixtures/stream_with_tool_calls", .{if (std.c.getenv("MOCK_SERVER_URL")) |v| std.mem.span(v) else "http://localhost:8080"}, 0);
    defer std.heap.c_allocator.free(_mock_url);
    var _client = try liter_llm.create_client("test-key", _mock_url, null, null, null);
    defer _client.free();
    const _req_z = try std.heap.c_allocator.dupeZ(u8, "{\"messages\":[{\"content\":\"What is the weather in NYC?\",\"role\":\"user\"}],\"model\":\"gpt-4\",\"stream\":true,\"tools\":[{\"function\":{\"description\":\"Get the current weather for a given location\",\"name\":\"get_weather\",\"parameters\":{\"properties\":{\"location\":{\"description\":\"The city and state, e.g. New York, NY\",\"type\":\"string\"}},\"required\":[\"location\"],\"type\":\"object\"}},\"type\":\"function\"}]}");
    defer std.heap.c_allocator.free(_req_z);
    const _req_handle = liter_llm.c.literllm_chat_completion_request_from_json(_req_z.ptr);
    defer liter_llm.c.literllm_chat_completion_request_free(_req_handle);
    const _stream_handle = liter_llm.c.literllm_default_client_chat_stream_start(@as(*liter_llm.c.LITERLLMDefaultClient, @ptrCast(_client._handle)), _req_handle);
    if (_stream_handle == null) return error.StreamStartFailed;
    defer liter_llm.c.literllm_default_client_chat_stream_free(_stream_handle);
    var chunks: std.ArrayList([]u8) = .empty;
    defer {
        for (chunks.items) |_cj| std.heap.c_allocator.free(_cj);
        chunks.deinit(std.heap.c_allocator);
    }
    var chunks_content: std.ArrayList(u8) = .empty;
    defer chunks_content.deinit(std.heap.c_allocator);
    while (true) {
        const _nc = liter_llm.c.literllm_default_client_chat_stream_next(_stream_handle);
        if (_nc == null) break;
        const _np = liter_llm.c.literllm_chat_completion_chunk_to_json(_nc);
        liter_llm.c.literllm_chat_completion_chunk_free(_nc);
        if (_np == null) continue;
        const _ns = std.mem.span(_np);
        const _nj = try std.heap.c_allocator.dupe(u8, _ns);
        liter_llm.c.literllm_free_string(_np);
        if (std.json.parseFromSlice(std.json.Value, std.heap.c_allocator, _nj, .{})) |_cp| {
            defer _cp.deinit();
            if (_cp.value.object.get("choices")) |_chs|
                if (_chs.array.items.len > 0)
                    if (_chs.array.items[0].object.get("delta")) |_dl|
                        if (_dl.object.get("content")) |_ct|
                            if (_ct == .string) try chunks_content.appendSlice(std.heap.c_allocator, _ct.string);
        } else |_| {}
        try chunks.append(std.heap.c_allocator, _nj);
    }
    try testing.expect(chunks.items.len >= 4);
    try testing.expectEqualStrings("tool_calls", (blk: { if (chunks.items.len == 0) break :blk ""; var _lcp = std.json.parseFromSlice(std.json.Value, std.heap.c_allocator, chunks.items[chunks.items.len - 1], .{}) catch break :blk ""; defer _lcp.deinit(); if (_lcp.value.object.get("choices")) |_lchs| if (_lchs.array.items.len > 0) if (_lchs.array.items[0].object.get("finish_reason")) |_fr| if (_fr == .string) break :blk _fr.string; break :blk ""; }));
    try testing.expect(chunks.items.len > 0);
}

test "stream_with_usage" {
    // Streaming chat completion that includes a usage summary in the final chunk
    var gpa: std.heap.DebugAllocator(.{}) = .init;
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    const _mock_url = try std.fmt.allocPrintSentinel(std.heap.c_allocator, "{s}/fixtures/stream_with_usage", .{if (std.c.getenv("MOCK_SERVER_URL")) |v| std.mem.span(v) else "http://localhost:8080"}, 0);
    defer std.heap.c_allocator.free(_mock_url);
    var _client = try liter_llm.create_client("test-key", _mock_url, null, null, null);
    defer _client.free();
    const _req_z = try std.heap.c_allocator.dupeZ(u8, "{\"messages\":[{\"content\":\"Say hi\",\"role\":\"user\"}],\"model\":\"gpt-4\",\"stream\":true,\"stream_options\":{\"include_usage\":true}}");
    defer std.heap.c_allocator.free(_req_z);
    const _req_handle = liter_llm.c.literllm_chat_completion_request_from_json(_req_z.ptr);
    defer liter_llm.c.literllm_chat_completion_request_free(_req_handle);
    const _stream_handle = liter_llm.c.literllm_default_client_chat_stream_start(@as(*liter_llm.c.LITERLLMDefaultClient, @ptrCast(_client._handle)), _req_handle);
    if (_stream_handle == null) return error.StreamStartFailed;
    defer liter_llm.c.literllm_default_client_chat_stream_free(_stream_handle);
    var chunks: std.ArrayList([]u8) = .empty;
    defer {
        for (chunks.items) |_cj| std.heap.c_allocator.free(_cj);
        chunks.deinit(std.heap.c_allocator);
    }
    var chunks_content: std.ArrayList(u8) = .empty;
    defer chunks_content.deinit(std.heap.c_allocator);
    while (true) {
        const _nc = liter_llm.c.literllm_default_client_chat_stream_next(_stream_handle);
        if (_nc == null) break;
        const _np = liter_llm.c.literllm_chat_completion_chunk_to_json(_nc);
        liter_llm.c.literllm_chat_completion_chunk_free(_nc);
        if (_np == null) continue;
        const _ns = std.mem.span(_np);
        const _nj = try std.heap.c_allocator.dupe(u8, _ns);
        liter_llm.c.literllm_free_string(_np);
        if (std.json.parseFromSlice(std.json.Value, std.heap.c_allocator, _nj, .{})) |_cp| {
            defer _cp.deinit();
            if (_cp.value.object.get("choices")) |_chs|
                if (_chs.array.items.len > 0)
                    if (_chs.array.items[0].object.get("delta")) |_dl|
                        if (_dl.object.get("content")) |_ct|
                            if (_ct == .string) try chunks_content.appendSlice(std.heap.c_allocator, _ct.string);
        } else |_| {}
        try chunks.append(std.heap.c_allocator, _nj);
    }
    const _result_json = if (chunks.items.len > 0) chunks.items[chunks.items.len - 1] else &[_]u8{};
    var _parsed = try std.json.parseFromSlice(std.json.Value, allocator, _result_json, .{});
    defer _parsed.deinit();
    const result = &_parsed.value;
    try testing.expect(chunks.items.len >= 3);
    try testing.expectEqualStrings("Hi there!", chunks_content.items);
    try testing.expectEqual(18, result.object.get("usage").?.object.get("total_tokens").?.integer);
}

test "vertex_stream" {
    // Streaming chat completion via the Google Vertex AI provider using the vertex_ai/ prefix — verifies SSE chunks from the Gemini streaming endpoint are yielded and assembled correctly
    const _mock_url = try std.fmt.allocPrintSentinel(std.heap.c_allocator, "{s}/fixtures/vertex_stream", .{if (std.c.getenv("MOCK_SERVER_URL")) |v| std.mem.span(v) else "http://localhost:8080"}, 0);
    defer std.heap.c_allocator.free(_mock_url);
    var _client = try liter_llm.create_client("test-key", _mock_url, null, null, null);
    defer _client.free();
    const _req_z = try std.heap.c_allocator.dupeZ(u8, "{\"max_tokens\":32,\"messages\":[{\"content\":\"Count to three, one word per response.\",\"role\":\"user\"}],\"model\":\"vertex_ai/gemini-2.0-flash\",\"stream\":true}");
    defer std.heap.c_allocator.free(_req_z);
    const _req_handle = liter_llm.c.literllm_chat_completion_request_from_json(_req_z.ptr);
    defer liter_llm.c.literllm_chat_completion_request_free(_req_handle);
    const _stream_handle = liter_llm.c.literllm_default_client_chat_stream_start(@as(*liter_llm.c.LITERLLMDefaultClient, @ptrCast(_client._handle)), _req_handle);
    if (_stream_handle == null) return error.StreamStartFailed;
    defer liter_llm.c.literllm_default_client_chat_stream_free(_stream_handle);
    var chunks: std.ArrayList([]u8) = .empty;
    defer {
        for (chunks.items) |_cj| std.heap.c_allocator.free(_cj);
        chunks.deinit(std.heap.c_allocator);
    }
    var chunks_content: std.ArrayList(u8) = .empty;
    defer chunks_content.deinit(std.heap.c_allocator);
    while (true) {
        const _nc = liter_llm.c.literllm_default_client_chat_stream_next(_stream_handle);
        if (_nc == null) break;
        const _np = liter_llm.c.literllm_chat_completion_chunk_to_json(_nc);
        liter_llm.c.literllm_chat_completion_chunk_free(_nc);
        if (_np == null) continue;
        const _ns = std.mem.span(_np);
        const _nj = try std.heap.c_allocator.dupe(u8, _ns);
        liter_llm.c.literllm_free_string(_np);
        if (std.json.parseFromSlice(std.json.Value, std.heap.c_allocator, _nj, .{})) |_cp| {
            defer _cp.deinit();
            if (_cp.value.object.get("choices")) |_chs|
                if (_chs.array.items.len > 0)
                    if (_chs.array.items[0].object.get("delta")) |_dl|
                        if (_dl.object.get("content")) |_ct|
                            if (_ct == .string) try chunks_content.appendSlice(std.heap.c_allocator, _ct.string);
        } else |_| {}
        try chunks.append(std.heap.c_allocator, _nj);
    }
    try testing.expect(chunks.items.len >= 2);
    try testing.expectEqualStrings("One Two Three", chunks_content.items);
    try testing.expect(chunks.items.len > 0);
}
